def balanced(s):
    """Returns True if parentheses in the string are balanced."""
    stack = []
    for c in s:
        if c == '(':
            stack.append(c)
        elif c == ')':
            if not stack:
                return False  # edge case: no opening parenthesis before closing one
            stack.pop()
    return not stack  # an empty stack means balanced parentheses
